const __pageData = JSON.parse('{"title":"排版与布局：网格系统与可读性","description":"从排版可读性理论到现代CSS网格系统的完整映射，涵盖字体心理学、垂直节奏、响应式排版及设计系统Tokens的工程实现","frontmatter":{"title":"排版与布局：网格系统与可读性","description":"从排版可读性理论到现代CSS网格系统的完整映射，涵盖字体心理学、垂直节奏、响应式排版及设计系统Tokens的工程实现","date":"2026-05-01T00:00:00.000Z","tags":["UI原理","排版","网格系统","可读性","CSS","Tailwind","响应式设计"],"category":"theoretical-foundations"},"headers":[],"relativePath":"ui-principles/06-typography-layout-grid.md","filePath":"ui-principles/06-typography-layout-grid.md","lastUpdated":1777713329000}');
